// Validate input and set defaults
const body = $input.first().json.body || $input.first().json;
const username = body.username;

if (!username) {
  throw new Error('Missing required field: username');
}

return [{ json: { username: username.toLowerCase().replace('@', '') } }];

const runData = $input.first().json;
const runId = runData.data?.id;

if (!runId) {
  throw new Error('Apify run did not start: ' + JSON.stringify(runData));
}

// Pass run ID and original username downstream
const username = $('Validate Input').first().json.username;

return [{ json: { apify_run_id: runId, username, status: runData.data.status } }];

const runData = $input.first().json;
const status = runData.data?.status;
const apify_run_id = $('Extract Run ID').first().json.apify_run_id;
const username = $('Extract Run ID').first().json.username;

// SUCCEEDED or FAILED/ABORTED stop the loop
const done = ['SUCCEEDED', 'FAILED', 'ABORTED', 'TIMED-OUT'].includes(status);

if (status === 'FAILED' || status === 'ABORTED' || status === 'TIMED-OUT') {
  throw new Error(`Apify run ${apify_run_id} ended with status: ${status}`);
}

return [{ json: { apify_run_id, username, status, done } }];

// Transform Apify Instagram post data to our posts table schema
// The HTTP node returns the array as a single item — unwrap it
const raw = $input.all();
const firstItem = raw[0]?.json;
const items = Array.isArray(firstItem) ? firstItem.map(d => ({ json: d })) : raw;
const username = $('Extract Run ID').first().json.username;

const transformed = items.map(item => {
  const d = item.json;

  // Detect content type
  let content_type = 'image';
  if (d.type === 'Video' || d.videoUrl) content_type = 'reel';
  else if (d.type === 'Sidecar' || (d.images && d.images.length > 1)) content_type = 'carousel';

  // Extract hashtags from caption
  const caption = d.caption || d.text || '';
  const hashtagMatches = caption.match(/#[\w]+/g) || [];
  const hashtags = [...new Set(hashtagMatches.map(h => h.toLowerCase()))];

  // Metrics — Apify field names vary slightly by scraper version
  const likes = d.likesCount ?? d.likes ?? 0;
  const comments = d.commentsCount ?? d.comments ?? 0;
  const shares = d.sharesCount ?? d.shares ?? 0;
  const views = d.videoViewCount ?? d.videoPlayCount ?? d.views ?? 0;
  const followers = d.ownerFollowersCount ?? 1; // fallback to avoid div/0

  // Engagement rate: (likes + comments) / followers * 100
  const engagement_rate = followers > 0
    ? parseFloat(((likes + comments) / followers * 100).toFixed(4))
    : 0;

  const platform_post_id = d.shortCode || d.id || d.url?.split('/p/')?.[1]?.replace(/\/.*/, '') || String(d.timestamp);

  return {
    json: {
      profile_username: username,
      platform_post_id,
      content_type,
      caption: caption.substring(0, 2000),
      hashtags,
      likes,
      comments,
      shares,
      views,
      engagement_rate,
      posted_at: d.timestamp ? new Date(typeof d.timestamp === 'number' ? d.timestamp * 1000 : d.timestamp).toISOString() : null,
      // Pass follower count for profile update
      owner_followers: d.ownerFollowersCount ?? null,
      owner_following: d.ownerFollowingCount ?? null,
      owner_bio: d.ownerBiography ?? null,
    }
  };
}).filter(item => item.json.platform_post_id);

console.log(`Transformed ${transformed.length} posts for @${username}`);
return transformed;

// Upsert or create the profile record, return its ID
const item = $input.first().json;
const username = item.profile_username;

// We'll look up / create the profile in the next HTTP node.
// Just pass through with profile lookup data.
return [{
  json: {
    ...item,
    platform: 'instagram',
    username
  }
}];

// Combine profile ID from upsert response with post data
// Also recalculate engagement_rate using real follower count from profile
const profileResp = $input.first().json;
const profileArr = Array.isArray(profileResp) ? profileResp : [profileResp];
const profile = profileArr[0];
const profileId = profile?.id;
const profileFollowers = profile?.followers || null;

if (!profileId) {
  throw new Error('Profile upsert did not return an ID: ' + JSON.stringify(profileResp));
}

const allPosts = $('Transform Posts').all();

return allPosts.map(p => {
  const likes = p.json.likes || 0;
  const comments = p.json.comments || 0;
  // Use real profile followers if available, else per-post owner count, else null
  const followers = profileFollowers || p.json.owner_followers || null;
  const engagement_rate = (followers && followers > 0)
    ? parseFloat(((likes + comments) / followers * 100).toFixed(4))
    : null;

  return {
    json: {
      profile_id: profileId,
      platform_post_id: p.json.platform_post_id,
      content_type: p.json.content_type,
      caption: p.json.caption,
      hashtags: p.json.hashtags,
      likes,
      comments,
      shares: p.json.shares,
      views: p.json.views,
      engagement_rate,
      posted_at: p.json.posted_at,
    }
  };
});

// After all posts upserted, update last_scraped on the profile
const allPosts = $('Attach Profile ID').all();
const profileId = allPosts[0]?.json?.profile_id;
const postsCount = allPosts.length;
const apifyRunId = $('Extract Run ID').first().json.apify_run_id;

return [{ json: { profile_id: profileId, posts_count: postsCount, apify_run_id: apifyRunId } }];
